def extract_embedded_csv(source_text):
    quote = "'''"
    pattern = r"StringIO\(\s*" + re.escape(quote) + r"(.*?)" + re.escape(quote) + r"\s*\)"
    match = re.search(pattern, source_text, flags=re.DOTALL)
    if match is None:
        return source_text.strip()
    return match.group(1).strip()

def read_leachate_from_embedded_text(source_text):
    csv_text = extract_embedded_csv(source_text)
    df = pd.read_csv(io.StringIO(csv_text), dtype=str)
    df = df[~df["Column/Pot"].astype(str).str.contains("Column/Pot", na=False)].copy()
    df = df[~df["date "].astype(str).str.contains("date", na=False)].copy()
    df = df.dropna(subset=["Column/Pot", "date "])
    df["date"] = pd.to_datetime(df["date "], format="%d.%m.%Y", errors="coerce")
    df = df.dropna(subset=["date"])
    numeric_cols = ["Volume in l", "Na+ mmol", "K+ mmol", "Ca2+ mmol", "Mg2+ mmol", "NH4+ mmol", "F- mmol", "Cl- mmol", "HCO3- mmol", "NO3- mmol", "NO2- mmol", "SO4 2- mmol", "DOC mmol", "Fe mmol", "Al mmol", "Si mmol", "pH ", "O2 %", "Conductivity uS/cm", "hydrogen ions (hydron) [H⁺]", "HCO3- umol/l"]
    for col in numeric_cols:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce")
    df["Treatment"] = df["Treatment"].astype(str).str.strip()
    df["Column/Pot"] = df["Column/Pot"].astype(str).str.strip()
    df = df[(df["date"] >= pd.to_datetime(START_DATE)) & (df["date"] <= pd.to_datetime(END_DATE))]
    return df

def read_export_excel(path):
    df = pd.read_excel(path, sheet_name="Export")
    df["Timestamp"] = pd.to_datetime(df["Timestamp"], errors="coerce")
    return df.dropna(subset=["Timestamp"]).sort_values("Timestamp")

def clean_rain(df):
    rain = df.copy()
    rain["rain"] = pd.to_numeric(rain["rain"], errors="coerce").fillna(0.0)
    rain["rain"] = rain["rain"].clip(lower=0.0)
    rain = rain.groupby("Timestamp", as_index=True)["rain"].sum().to_frame()
    return rain.loc[START_DATE:END_DATE].sort_index()

def clean_moisture(df):
    out = df.copy()
    sensor_cols = [c for c in out.columns if c not in ["Timestamp", "Entity Name"]]
    for col in sensor_cols:
        out[col] = pd.to_numeric(out[col], errors="coerce")
    out = out[["Timestamp"] + sensor_cols].set_index("Timestamp").sort_index()
    out.columns = [c.strip() for c in out.columns]
    return out.loc[START_DATE:END_DATE]

def simplify_sensor_name(col):
    name = col.strip().replace("EC.30.", "").replace("EC.60.", "")
    return name.split("(")[0].strip()

def aggregate_moisture_sensors(df, method):
    if method == "mean":
        return df.mean(axis=1, skipna=True)
    if method == "median":
        return df.median(axis=1, skipna=True)
    raise ValueError(f"MOISTURE_AGGREGATION must be 'mean' or 'median', not {method!r}.")

rain_path = os.path.join(DATA_DIR, RAIN_FILE)
moisture_path = os.path.join(DATA_DIR, MOISTURE_FILE)
moisture60_path = os.path.join(DATA_DIR, MOISTURE60_FILE)

rain = clean_rain(read_export_excel(rain_path))
moisture = clean_moisture(read_export_excel(moisture_path))
moisture60 = clean_moisture(read_export_excel(moisture60_path))
leachate = read_leachate_from_embedded_text(LEACHATE_SOURCE)

sensor_map = {simplify_sensor_name(c): c for c in moisture.columns}
sensor_map60 = {simplify_sensor_name(c): c for c in moisture60.columns}

print("Available 30 cm moisture sensors:")
print(sorted(sensor_map.keys()))

print("Available 60 cm moisture sensors:")
print(sorted(sensor_map60.keys()))

if SELECTED_SENSOR is not None and SELECTED_SENSOR not in sensor_map:
    raise ValueError(f"SELECTED_SENSOR={SELECTED_SENSOR} not found in 30 cm sensors.")

if SELECTED_SENSOR is not None and SELECTED_SENSOR not in sensor_map60:
    raise ValueError(f"SELECTED_SENSOR={SELECTED_SENSOR} not found in 60 cm sensors.")

if SELECTED_SENSOR is None:
    theta_series = aggregate_moisture_sensors(moisture, MOISTURE_AGGREGATION).rename(f"theta30_{MOISTURE_AGGREGATION}")
    theta60_series = aggregate_moisture_sensors(moisture60, MOISTURE_AGGREGATION).rename(f"theta60_{MOISTURE_AGGREGATION}")
    sensor_label = f"{MOISTURE_AGGREGATION}_all_sensors"
else:
    theta_series = moisture[sensor_map[SELECTED_SENSOR]].rename("theta30")
    theta60_series = moisture60[sensor_map60[SELECTED_SENSOR]].rename("theta60")
    sensor_label = SELECTED_SENSOR

rain_weekly = rain.resample("7D").sum()
theta_weekly = theta_series.resample("7D").mean().interpolate(limit=2)
theta60_weekly = theta60_series.resample("7D").mean().interpolate(limit=2)

if SELECTED_SENSOR is None:
    theta_weekly_std = moisture.resample("7D").mean().std(axis=1, skipna=True).interpolate(limit=2)
    theta60_weekly_std = moisture60.resample("7D").mean().std(axis=1, skipna=True).interpolate(limit=2)
else:
    theta_weekly_std = None
    theta60_weekly_std = None

leachate = leachate.dropna(subset=["Treatment"])
leachate_selected = leachate[leachate["Treatment"].isin(SELECTED_TREATMENTS)].copy()

if leachate_selected.empty:
    leachate_selected = leachate.copy()

chem_vars = ["HCO3- mmol", "Ca2+ mmol", "Mg2+ mmol", "Conductivity uS/cm", "pH "]
chem_daily = leachate_selected.groupby(["date", "Treatment"], as_index=False)[chem_vars].mean(numeric_only=True)

fig, axes = plt.subplots(4, 1, figsize=(13, 11), sharex=True, dpi=120, gridspec_kw={"height_ratios": [0.8, 1.0, 1.5, 1.8], "hspace": 0.0})

for ax, label in zip(axes, ["(a)", "(b)", "(c)", "(d)"]):
    ax.text(
        0.012, 0.90, label,
        transform=ax.transAxes,
        ha="left",
        va="top",
        fontsize=12,
        fontweight="bold",
        bbox={"facecolor": "white", "edgecolor": "none", "alpha": 0.75, "pad": 1.5},
    )

